// src/components/ResourcePanel.js
import React, { useState, useEffect, useCallback } from "react";
import { getResources, getZones, updateResource, createResource, deleteResource, createAllocation } from "../services/api";
import "./ResourcePanel.css";

const TYPE_COLOR = { medical: "#EF4444", rescue: "#F59E0B", food: "#10B981", shelter: "#3B82F6" };
const TYPE_ICON = { medical: "🏥", rescue: "🚒", food: "🍎", shelter: "⛺" };
const STATUS_ORDER = { deployed: 0, "in-transit": 1, standby: 2, unavailable: 3 };

export default function ResourcePanel({ tick }) {
  const [resources, setResources] = useState([]);
  const [zones, setZones] = useState([]);
  const [filter, setFilter] = useState("all");
  const [typeFilter, setTypeFilter] = useState("all");
  const [selected, setSelected] = useState(null);
  const [loading, setLoading] = useState(true);

  // Selection and Action States
  const [actionZoneId, setActionZoneId] = useState("");
  const [actionMessage, setActionMessage] = useState("");
  const [actionError, setActionError] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [lookupZoneId, setLookupZoneId] = useState("");

  // Add Resource and Partial Dispatch states
  const [showAddForm, setShowAddForm] = useState(false);
  const [newResourceName, setNewResourceName] = useState("");
  const [newResourceType, setNewResourceType] = useState("medical");
  const [newResourceLocation, setNewResourceLocation] = useState("Base Camp — Hyderabad");
  const [newResourceCapacity, setNewResourceCapacity] = useState(500);
  const [dispatchUnits, setDispatchUnits] = useState(0);

  // Sync dispatchUnits when selected resource changes
  useEffect(() => {
    if (selected) {
      setDispatchUnits(selected.capacity - selected.utilized);
    } else {
      setDispatchUnits(0);
    }
  }, [selected]);

  const fetchData = useCallback(async () => {
    try {
      const [resData, zonesData] = await Promise.all([getResources(), getZones()]);
      setResources(resData);
      setZones(zonesData);
      setLoading(false);
    } catch (err) {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [tick, fetchData]);

  // Keep selected item details in sync if database updates
  useEffect(() => {
    if (selected) {
      const current = resources.find(r => r.id === selected.id);
      if (current) {
        setSelected(current);
      }
    }
  }, [resources, selected]);

  const filtered = resources
    .filter((r) => filter === "all" || r.status === filter)
    .filter((r) => typeFilter === "all" || r.resource_type === typeFilter)
    .sort((a, b) => (STATUS_ORDER[a.status] ?? 9) - (STATUS_ORDER[b.status] ?? 9));

  const counts = {
    all: resources.length,
    deployed: resources.filter((r) => r.status === "deployed").length,
    "in-transit": resources.filter((r) => r.status === "in-transit").length,
    standby: resources.filter((r) => r.status === "standby").length,
  };

  // Group resources by location for live tracker summary
  const locationsInventory = React.useMemo(() => {
    const groups = {};

    resources.forEach((r) => {
      const locName = r.assigned_zone_name 
        ? r.assigned_zone_name.split("—")[0].trim() 
        : r.location || "Unknown Location";

      if (!groups[locName]) {
        groups[locName] = {
          name: locName,
          resourceCount: 0,
          totalCapacity: 0,
          totalUtilized: 0
        };
      }

      groups[locName].resourceCount += 1;
      groups[locName].totalCapacity += r.capacity || 0;
      groups[locName].totalUtilized += r.utilized || 0;
    });

    return Object.values(groups).sort((a, b) => b.resourceCount - a.resourceCount);
  }, [resources]);

  // Get currently selected lookup location info
  const lookupData = React.useMemo(() => {
    if (!lookupZoneId) return null;

    // Check if lookupZoneId is a zone ID (number)
    const zoneId = parseInt(lookupZoneId);
    if (!isNaN(zoneId)) {
      const zone = zones.find((z) => z.id === zoneId);
      if (zone) {
        const name = zone.name.split("—")[0].trim();
        const allocated = resources.filter((r) => r.assigned_zone === zoneId);
        return { name, type: "field", details: `${zone.district}, ${zone.state}`, allocated };
      }
    }

    // Otherwise it's a base camp name
    const allocated = resources.filter((r) => {
      const locName = r.assigned_zone_name 
        ? r.assigned_zone_name.split("—")[0].trim() 
        : r.location;
      return locName === lookupZoneId;
    });
    return { name: lookupZoneId, type: "base", details: "Emergency Staging Base Camp", allocated };
  }, [lookupZoneId, zones, resources]);

  // Dispatch selected asset (or subset of units) to a target zone
  const handleDispatch = async () => {
    if (!selected || !actionZoneId) return;

    const remainingUnits = selected.capacity - selected.utilized;
    if (dispatchUnits <= 0 || dispatchUnits > remainingUnits) {
      setActionError(`Invalid dispatch amount. Must be between 1 and ${remainingUnits}.`);
      return;
    }

    setSubmitting(true);
    setActionMessage("");
    setActionError("");
    const targetZone = zones.find(z => z.id === parseInt(actionZoneId));

    try {
      const isFullDispatch = dispatchUnits === remainingUnits && selected.utilized === 0;

      if (isFullDispatch) {
        // Simple case: dispatch the entire asset
        await createAllocation({
          zone: targetZone.id,
          resource: selected.id,
          notes: `Quick dispatched via Resource Inventory`
        });

        // Update the resource capacity metrics (mark all as utilized)
        await updateResource(selected.id, {
          utilized: selected.capacity,
          status: 'in-transit',
          assigned_zone: targetZone.id,
          location: `En route to ${targetZone.name.split('—')[0].strip()}`
        });

        setActionMessage(`Successfully dispatched entire unit ${selected.name} to ${targetZone.name.split("—")[0].trim()}`);
      } else {
        // Partial dispatch:
        // 1. Deduct from parent standby resource (increase parent utilized)
        const newParentUtilized = selected.utilized + dispatchUnits;
        await updateResource(selected.id, {
          utilized: newParentUtilized
        });

        // 2. Create a sub-resource branch at the target zone
        const branchResource = await createResource({
          name: `${selected.name} (${targetZone.name.split("—")[0].trim()} Branch)`,
          resource_type: selected.resource_type,
          status: "deployed",
          assigned_zone: targetZone.id,
          capacity: dispatchUnits,
          utilized: dispatchUnits,
          location: `Deployed from Resource #${selected.id}`
        });

        // 3. Create allocation for the branch
        await createAllocation({
          zone: targetZone.id,
          resource: branchResource.id,
          notes: `Partial allocation from parent standby pool (Resource #${selected.id})`
        });

        setActionMessage(`Successfully dispatched ${dispatchUnits} units of ${selected.name} to ${targetZone.name.split("—")[0].trim()}`);
      }

      setActionZoneId("");
      await fetchData();
    } catch (err) {
      setActionError("Failed to dispatch resource. Please try again.");
    } finally {
      setSubmitting(false);
    }
  };

  // Recall active asset to Base Camp
  const handleRecall = async () => {
    if (!selected) return;
    setSubmitting(true);
    setActionMessage("");
    setActionError("");

    try {
      // Check if this is a deployed branch from a parent resource
      const parentIdMatch = selected.location ? selected.location.match(/Deployed from Resource #(\d+)/) : null;

      if (parentIdMatch) {
        const parentId = parseInt(parentIdMatch[1]);
        const parentRes = resources.find(r => r.id === parentId);

        if (parentRes) {
          // Return the capacity back to the parent standby pool
          const newParentUtilized = Math.max(0, parentRes.utilized - selected.capacity);
          await updateResource(parentId, {
            utilized: newParentUtilized
          });
        }

        // Delete the branch resource since it is recalled
        await deleteResource(selected.id);

        setActionMessage(`Successfully recalled ${selected.name} and returned units to standby pool.`);
        setSelected(null); // Deselect because the branch resource is deleted
      } else {
        // Standard recall for a main resource
        await updateResource(selected.id, {
          status: "standby",
          assigned_zone: null,
          location: "Base Camp — Hyderabad",
          utilized: 0
        });
        setActionMessage(`Successfully recalled ${selected.name} to Base Camp.`);
      }

      await fetchData();
    } catch (err) {
      setActionError("Failed to recall resource.");
    } finally {
      setSubmitting(false);
    }
  };

  // Re-route active asset to a different zone
  const handleReroute = async () => {
    if (!selected || !actionZoneId) return;
    setSubmitting(true);
    setActionMessage("");
    setActionError("");
    const targetZone = zones.find(z => z.id === parseInt(actionZoneId));

    try {
      await updateResource(selected.id, {
        assigned_zone: targetZone.id,
        status: "in-transit",
        location: `En route to ${targetZone.name.split("—")[0].trim()}`
      });
      setActionMessage(`Re-routed ${selected.name} to ${targetZone.name.split("—")[0].trim()}`);
      setActionZoneId("");
      await fetchData();
    } catch (err) {
      setActionError("Failed to re-route resource.");
    } finally {
      setSubmitting(false);
    }
  };

  // Create new Resource Pool
  const handleCreateResource = async (e) => {
    e.preventDefault();
    if (!newResourceName.trim()) {
      setActionError("Please enter a valid resource name.");
      return;
    }
    if (newResourceCapacity <= 0) {
      setActionError("Total capacity must be greater than 0.");
      return;
    }

    setSubmitting(true);
    setActionMessage("");
    setActionError("");

    try {
      await createResource({
        name: newResourceName.trim(),
        resource_type: newResourceType,
        status: "standby",
        location: newResourceLocation.trim(),
        capacity: newResourceCapacity,
        utilized: 0
      });
      setActionMessage(`Successfully created standby resource ${newResourceName}!`);
      setNewResourceName("");
      setNewResourceCapacity(500);
      setShowAddForm(false);
      await fetchData();
    } catch (err) {
      setActionError("Failed to create new resource.");
    } finally {
      setSubmitting(false);
    }
  };

  if (loading) {
    return (
      <div className="page" style={{ display: "flex", alignItems: "center", justifyContent: "center", minHeight: 400 }}>
        <div style={{ textAlign: "center", color: "var(--slate)" }}>
          <div className="analyze-spinner" style={{ margin: "0 auto 16px" }} />
          <div>Loading resources...</div>
        </div>
      </div>
    );
  }

  return (
    <div className="page">
      <div className="page-header">
        <h1>Resource Inventory</h1>
        <p>Full inventory of emergency resources with real-time status and utilization</p>
      </div>

      {/* Summary KPI row */}
      <div className="grid-4" style={{ marginBottom: 20 }}>
        {[
          { label: "Total Resources", val: resources.length, sub: "All types", cls: "blue" },
          { label: "Deployed", val: counts.deployed, sub: "Active in field", cls: "green" },
          { label: "In Transit", val: counts["in-transit"], sub: "En route", cls: "amber" },
          { label: "Standby", val: counts.standby, sub: "Ready to deploy", cls: "critical" },
        ].map((k) => (
          <div key={k.label} className={`stat-card ${k.cls}`}>
            <div className="stat-label">{k.label}</div>
            <div className="stat-value">{k.val}</div>
            <div className="stat-sub">{k.sub}</div>
          </div>
        ))}
      </div>

      {/* Filters */}
      <div className="card" style={{ marginBottom: 16 }}>
        <div style={{ display: "flex", gap: 8, flexWrap: "wrap", alignItems: "center" }}>
          <span style={{ fontSize: 11, color: "var(--slate)", marginRight: 4 }}>STATUS:</span>
          {["all", "deployed", "in-transit", "standby"].map((s) => (
            <button
              key={s}
              className={`filter-chip ${filter === s ? "active" : ""}`}
              onClick={() => setFilter(s)}
            >
              {s === "all" ? "All" : s} ({counts[s] ?? resources.filter((r) => r.status === s).length})
            </button>
          ))}
          <div style={{ width: 1, height: 20, background: "var(--border)", margin: "0 4px" }} />
          <span style={{ fontSize: 11, color: "var(--slate)", marginRight: 4 }}>TYPE:</span>
          {["all", "medical", "rescue", "food", "shelter"].map((t) => (
            <button
              key={t}
              className={`filter-chip ${typeFilter === t ? "active" : ""}`}
              onClick={() => setTypeFilter(t)}
            >
              {t.charAt(0).toUpperCase() + t.slice(1)}
            </button>
          ))}
        </div>
      </div>

      {/* Interactive Two-Column Split Layout */}
      <div style={{ display: "flex", gap: "20px", alignItems: "flex-start", flexWrap: "wrap" }}>

        {/* Simplified Inventory Table Card */}
        <div className="card" style={{ flex: (selected || showAddForm) ? "1 1 64%" : "1 1 100%", transition: "all 0.3s ease" }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "12px" }}>
            <div>
              <div className="card-title">Inventory Database</div>
              <div style={{ fontSize: "12px", color: "var(--slate)" }}>
                Select any asset row to view command options, dispatch, or recall.
              </div>
            </div>
            {!selected && !showAddForm && (
              <button 
                onClick={() => {
                  setShowAddForm(true);
                  setActionMessage("");
                  setActionError("");
                }}
                className="btn btn-primary"
                style={{ padding: "6px 14px", fontSize: "12px", background: "var(--green)", borderColor: "var(--green)" }}
              >
                ➕ Add Resource Pool
              </button>
            )}
          </div>
          <div className="res-table">
            <div className="res-table-header">
              <span>Resource Name</span>
              <span>Category</span>
              <span>Status</span>
              <span>Current Location</span>
              <span>Usage</span>
              <span>Last Updated</span>
            </div>
            {filtered.map((r) => {
              const pct = r.capacity > 0 ? Math.round((r.utilized / r.capacity) * 100) : 0;
              const color = TYPE_COLOR[r.resource_type] || "#94A3B8";
              const isSelected = selected && selected.id === r.id;

              // Simplified Terminology: Combine Zone and Current location
              const currentLocation = r.assigned_zone_name 
                ? r.assigned_zone_name.split("—")[0].trim() 
                : r.location;

              return (
                <div 
                  key={r.id} 
                  className={`res-table-row ${isSelected ? "selected" : ""}`}
                  onClick={() => {
                    setSelected(isSelected ? null : r);
                    setActionMessage("");
                    setActionError("");
                    setActionZoneId("");
                  }}
                  style={{ cursor: "pointer" }}
                >
                  <div className="res-name-cell">
                    <div className="res-type-indicator" style={{ background: color }} />
                    <span style={{ display: "flex", gap: "6px", alignItems: "center" }}>
                      <span>{TYPE_ICON[r.resource_type]}</span>
                      <span>{r.name}</span>
                    </span>
                  </div>
                  <span>
                    <span className="badge badge-medium" style={{ borderColor: color, color }}>
                      {r.resource_type}
                    </span>
                  </span>
                  <span>
                    <span className={`badge badge-${r.status}`}>{r.status}</span>
                  </span>
                  <span style={{ fontSize: 12, fontWeight: r.assigned_zone ? 600 : 400, color: r.assigned_zone ? "var(--white)" : "var(--slate)" }}>
                    {currentLocation}
                  </span>
                  <div className="util-cell">
                    <div className="util-bar-track">
                      <div
                        className="util-bar-fill"
                        style={{
                          width: `${pct}%`,
                          background: pct >= 90 ? "#EF4444" : pct >= 60 ? "#F59E0B" : "#10B981",
                        }}
                      />
                    </div>
                    <span className="util-pct">{pct}%</span>
                  </div>
                  <span style={{ fontSize: 11, color: "var(--slate-dim)", fontFamily: "var(--font-mono)" }}>
                    {new Date(r.last_update).toLocaleTimeString()}
                  </span>
                </div>
              );
            })}
            {filtered.length === 0 && (
              <div style={{ color: "var(--slate)", fontSize: 12, padding: "20px 0", textAlign: "center" }}>
                No resources match the current filters.
              </div>
            )}
          </div>
        </div>

        {/* Right Asset Command Panel */}
        {selected && (
          <div 
            className="card" 
            style={{ 
              flex: "1 1 32%", 
              minWidth: "300px", 
              border: `1.5px solid ${TYPE_COLOR[selected.resource_type]}55`,
              boxShadow: `0 0 16px ${TYPE_COLOR[selected.resource_type]}11`
            }}
          >
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: "16px" }}>
              <div>
                <span style={{ fontSize: "10px", textTransform: "uppercase", color: TYPE_COLOR[selected.resource_type], fontWeight: 700, letterSpacing: "0.05em" }}>
                  {selected.resource_type} Asset
                </span>
                <h2 style={{ fontSize: "18px", margin: "4px 0 0 0", color: "var(--white)" }}>{selected.name}</h2>
              </div>
              <button 
                onClick={() => setSelected(null)}
                style={{ background: "transparent", border: "none", color: "var(--slate)", fontSize: "18px", cursor: "pointer" }}
              >
                ✕
              </button>
            </div>

            {/* Asset quick details */}
            <div style={{ display: "flex", flexDirection: "column", gap: "10px", background: "rgba(255,255,255,0.02)", padding: "12px", borderRadius: "6px", border: "1px solid rgba(255,255,255,0.05)", marginBottom: "16px" }}>
              <div style={{ display: "flex", justifyContent: "space-between", fontSize: "12px" }}>
                <span style={{ color: "var(--slate)" }}>Current Status</span>
                <span className={`badge badge-${selected.status}`}>{selected.status}</span>
              </div>
              <div style={{ display: "flex", justifyContent: "space-between", fontSize: "12px" }}>
                <span style={{ color: "var(--slate)" }}>Station / Location</span>
                <span style={{ color: "var(--white)", fontWeight: 500 }}>
                  {selected.assigned_zone_name ? selected.assigned_zone_name.split("—")[0].trim() : selected.location}
                </span>
              </div>
              <div style={{ display: "flex", justifyContent: "space-between", fontSize: "12px" }}>
                <span style={{ color: "var(--slate)" }}>Usage Level</span>
                <span style={{ color: selected.utilized >= selected.capacity ? "var(--red)" : "var(--green)", fontWeight: 700 }}>
                  {selected.utilized} / {selected.capacity} Units ({selected.capacity > 0 ? Math.round((selected.utilized / selected.capacity) * 100) : 0}%)
                </span>
              </div>
            </div>

            {/* Success and Error Toasts */}
            {actionMessage && (
              <div style={{ background: "rgba(16, 185, 129, 0.15)", border: "1px solid var(--green)", color: "var(--green)", padding: "10px", borderRadius: "6px", fontSize: "12px", marginBottom: "16px" }}>
                {actionMessage}
              </div>
            )}
            {actionError && (
              <div style={{ background: "rgba(239, 68, 68, 0.15)", border: "1px solid var(--red)", color: "var(--red)", padding: "10px", borderRadius: "6px", fontSize: "12px", marginBottom: "16px" }}>
                {actionError}
              </div>
            )}

            {/* Actions Form */}
            <div style={{ borderTop: "1px solid rgba(255,255,255,0.05)", paddingTop: "16px" }}>
              {selected.status === "standby" ? (
                <>
                  <h3 style={{ fontSize: "13px", margin: "0 0 10px 0", color: "var(--white)" }}>⚡ Dispatch Asset to Location</h3>
                  <div style={{ display: "flex", flexDirection: "column", gap: "10px" }}>
                    <select
                      value={actionZoneId}
                      onChange={(e) => setActionZoneId(e.target.value)}
                      style={{
                        background: "rgba(15, 23, 42, 0.8)",
                        border: "1px solid rgba(255, 255, 255, 0.15)",
                        color: "#fff",
                        borderRadius: "6px",
                        padding: "8px 12px",
                        fontSize: "12px",
                        width: "100%",
                        outline: "none"
                      }}
                    >
                      <option value="">Select target disaster zone...</option>
                      {zones.map(z => (
                        <option key={z.id} value={z.id}>
                          {z.name.split("—")[0].trim()} ({z.severity.toUpperCase()} · AI Score: {z.priority_score})
                        </option>
                      ))}
                    </select>
                    <button
                      onClick={handleDispatch}
                      disabled={submitting || !actionZoneId}
                      className="btn btn-primary"
                      style={{ width: "100%", justifyContent: "center", padding: "10px" }}
                    >
                      {submitting ? "Dispatching..." : "⚡ Dispatch Asset Now"}
                    </button>
                  </div>
                </>
              ) : (
                <div style={{ display: "flex", flexDirection: "column", gap: "12px" }}>
                  <div>
                    <h3 style={{ fontSize: "13px", margin: "0 0 10px 0", color: "var(--white)" }}>⚡ Re-route to Different Location</h3>
                    <div style={{ display: "flex", gap: "8px" }}>
                      <select
                        value={actionZoneId}
                        onChange={(e) => setActionZoneId(e.target.value)}
                        style={{
                          background: "rgba(15, 23, 42, 0.8)",
                          border: "1px solid rgba(255, 255, 255, 0.15)",
                          color: "#fff",
                          borderRadius: "6px",
                          padding: "8px 12px",
                          fontSize: "12px",
                          flex: 1,
                          outline: "none"
                        }}
                      >
                        <option value="">Select new zone...</option>
                        {zones.filter(z => z.id !== selected.assigned_zone).map(z => (
                          <option key={z.id} value={z.id}>
                            {z.name.split("—")[0].trim()} ({z.severity.toUpperCase()})
                          </option>
                        ))}
                      </select>
                      <button
                        onClick={handleReroute}
                        disabled={submitting || !actionZoneId}
                        className="btn btn-ghost"
                        style={{ fontSize: "11px", padding: "0 14px" }}
                      >
                        Re-route
                      </button>
                    </div>
                  </div>

                  <div style={{ borderTop: "1px solid rgba(255,255,255,0.05)", paddingTop: "12px" }}>
                    <h3 style={{ fontSize: "13px", margin: "0 0 6px 0", color: "var(--white)" }}>Recall Asset</h3>
                    <p style={{ fontSize: "11px", color: "var(--slate)", margin: "0 0 10px 0" }}>
                      Recall this asset back to the main Base Camp in Hyderabad. Status shifts back to standby.
                    </p>
                    <button
                      onClick={handleRecall}
                      disabled={submitting}
                      className="btn btn-ghost"
                      style={{ width: "100%", justifyContent: "center", color: "var(--red)", borderColor: "rgba(239, 68, 68, 0.2)" }}
                    >
                      {submitting ? "Recalling..." : "Recall to Base Camp"}
                    </button>
                  </div>
                </div>
              )}
            </div>
          </div>
        )}

      </div>

      {/* Allocation by Location Lookup Card */}
      <div className="card" style={{ marginTop: 24, width: "100%" }}>
        <div className="card-title">Live Resource Deployment by Location</div>
        <div style={{ fontSize: 12, color: "var(--slate)", marginBottom: 16 }}>
          Live tracker summarizing active emergency assets at each location. Select any location row below to inspect its allocated units.
        </div>

        <div style={{ display: "flex", flexDirection: "column", gap: 20 }}>
          {/* Location-wise Summary Table */}
          <div className="loc-inv-table">
            <div className="loc-inv-header">
              <span>Location / Station</span>
              <span>Resources Staged</span>
              <span>Total Used</span>
              <span>Total Remaining</span>
              <span>Average Utilization</span>
            </div>
            {locationsInventory.map((loc) => {
              const remaining = Math.max(0, loc.totalCapacity - loc.totalUtilized);
              const pct = loc.totalCapacity > 0 ? Math.round((loc.totalUtilized / loc.totalCapacity) * 100) : 0;

              // Determine if this location is currently selected
              const isSelected = lookupData && lookupData.name === loc.name;
              const isBaseCamp = loc.name.startsWith("Base Camp");

              return (
                <div
                  key={loc.name}
                  className={`loc-inv-row ${isSelected ? "selected" : ""}`}
                  onClick={() => {
                    // Find if there is a zone matching this location name
                    const zoneObj = zones.find(z => z.name.split("—")[0].trim() === loc.name);
                    if (zoneObj) {
                      setLookupZoneId(zoneObj.id.toString());
                    } else {
                      setLookupZoneId(loc.name);
                    }
                  }}
                  style={{ cursor: "pointer" }}
                >
                  <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                    <span style={{ fontSize: 14 }}>{isBaseCamp ? "🏢" : "📍"}</span>
                    <span style={{ fontWeight: 600, color: "var(--white)" }}>{loc.name}</span>
                    <span 
                      className={`badge badge-${isBaseCamp ? "standby" : "deployed"}`}
                      style={{ fontSize: 9, padding: "2px 6px", textTransform: "uppercase" }}
                    >
                      {isBaseCamp ? "Base Camp" : "Field Zone"}
                    </span>
                  </div>
                  <span style={{ fontSize: 12, color: "var(--slate)" }}>
                    {loc.resourceCount} {loc.resourceCount === 1 ? "unit" : "units"}
                  </span>
                  <span style={{ fontSize: 12, fontWeight: 500, color: "var(--slate)" }}>
                    {loc.totalUtilized.toLocaleString()} units
                  </span>
                  <span style={{ fontSize: 12, fontWeight: 500, color: "var(--white)" }}>
                    {remaining.toLocaleString()} units
                  </span>
                  <div className="util-cell">
                    <div className="util-bar-track">
                      <div
                        className="util-bar-fill"
                        style={{
                          width: `${pct}%`,
                          background: pct >= 90 ? "var(--red)" : pct >= 60 ? "var(--amber)" : "var(--green)",
                        }}
                      />
                    </div>
                    <span className="util-pct">{pct}%</span>
                  </div>
                </div>
              );
            })}
          </div>

          {/* Allocation Details Section */}
          <div style={{ borderTop: "1px solid rgba(255,255,255,0.05)", paddingTop: 16 }}>
            {lookupData ? (
              <div>
                <h3 style={{ fontSize: 13, color: "var(--white)", marginBottom: 12, display: "flex", alignItems: "center", gap: 6 }}>
                  <span>Currently Staged at:</span>
                  <span style={{ color: "var(--blue)" }}>{lookupData.name}</span>
                  <span style={{ fontSize: 11, color: "var(--slate)", fontWeight: "normal" }}>({lookupData.details})</span>
                </h3>

                {lookupData.allocated.length === 0 ? (
                  <div style={{ color: "var(--slate)", fontSize: 12, padding: "16px 0", background: "rgba(255,255,255,0.01)", border: "1px dashed var(--border)", borderRadius: 6, textAlign: "center" }}>
                    No resources currently allocated to this location.
                  </div>
                ) : (
                  <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", gap: 12 }}>
                    {lookupData.allocated.map((r) => {
                      const pct = r.capacity > 0 ? Math.round((r.utilized / r.capacity) * 100) : 0;
                      return (
                        <div 
                          key={r.id}
                          style={{
                            background: "rgba(255, 255, 255, 0.02)",
                            border: "1px solid var(--border)",
                            borderRadius: 6,
                            padding: 12,
                            display: "flex",
                            flexDirection: "column",
                            gap: 8
                          }}
                        >
                          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                            <span style={{ fontSize: 13, fontWeight: 600, color: "var(--white)" }}>
                              {TYPE_ICON[r.resource_type]} {r.name}
                            </span>
                            <span className={`badge badge-${r.status}`}>{r.status}</span>
                          </div>

                          <div style={{ display: "flex", justifyContent: "space-between", fontSize: 11, color: "var(--slate)" }}>
                            <span>Usage: {pct}%</span>
                            <span>{r.utilized} / {r.capacity} Units</span>
                          </div>

                          <div className="util-bar-track" style={{ height: 4 }}>
                            <div
                              className="util-bar-fill"
                              style={{
                                width: `${pct}%`,
                                background: pct >= 90 ? "#EF4444" : pct >= 60 ? "#F59E0B" : "#10B981",
                              }}
                            />
                          </div>
                        </div>
                      );
                    })}
                  </div>
                )}
              </div>
            ) : (
              <div style={{ color: "var(--slate)", fontSize: 12, padding: "20px 0", background: "rgba(255,255,255,0.01)", border: "1px dashed var(--border)", borderRadius: 6, textAlign: "center" }}>
                💡 Select a location row above to inspect specific resource assignments.
              </div>
            )}
          </div>
        </div>
      </div>

    </div>
  );
}
